def transform(row):
    import re
    import math
    import datetime
    import calendar

    name = row[0]
    parts = re.split(r'[-\s]+', name)

    if len(parts) == 2:
        first = parts[0]
        last = parts[1]
        if len(first) == 3 and len(last) == 7:
            return first[0] + first[1] + first[2] + last[0] + last[1] + last[2] + last[3] + last[4] + last[5]
        elif len(first) == 3 and len(last) == 6:
            return first[0] + first[1] + first[2] + last[0] + last[1] + last[2] + last[3] + last[4] + last[5]
        elif len(first) == 3 and len(last) == 5:
            return first[0] + first[1] + first[2] + last[0] + last[1] + last[2] + last[3] + last[4]
        elif len(first) == 3 and len(last) == 4:
            return first[0] + first[1] + first[2] + last[0] + last[1] + last[2] + last[3]
        elif len(first) == 3 and len(last) == 3:
            return first[0] + first[1] + first[2] + last[0] + last[1] + last[2]
        elif len(first) == 3 and len(last) == 2

def transform(row):
    name = row[0]
    # Split name into first and last name
    parts = re.split(r'[-\s]+', name)
    if len(parts) == 2:
        first = parts[0]
        last = parts[1]
    else:
        first = name
        last = ""

    # Normalize first name
    first = first.strip()
    if first:
        first = first[0].upper() + first[1:]

    # Normalize last name
    last = last.strip()
    if last:
        last = last[0].upper() + last[1:]

    # Use the first letter of the last name as the output
    if last:
        return last[0]
    else:
        return first

