def transform(row):
    def round_to_nearest_integer(value):
        # Check if the value is a string and try to convert to float
        if isinstance(value, str):
            try:
                value = float(value)
            except ValueError:
                return value
        # Round to the nearest integer
        return round(value)

    def format_as_string(number):
        # Check if the number is an integer
        if number.is_integer():
            return f"{int(number)}.0"
        # Check if the number has a decimal part
        if isinstance(number, float) and number != int(number):
            # Check if the decimal part is .5 or .499...
            if number - int(number) >= 0.5:
                return f"{int(number) + 1}.0"
            else:
                return f"{int(number)}.0"
        return f"{int(number)}.0"

    # Extract the value from the row
    value = row[0]

    # Round to the nearest integer
    rounded_value = round_to_nearest_integer(value)

    # Format as a string
    return format_as_string(rounded_value)

def transform(row):
    value = row[0]
    # Check if the input is a valid number
    if not re.match(r'^-?\d+\.?\d*$', value):
        return value  # Return original if not a number

    # Split into integer and fractional parts
    parts = value.split('.')
    if len(parts) == 1:
        # No decimal point, treat as integer
        return value
    else:
        # Extract integer part and fractional part
        integer_part = parts[0]
        fractional_part = parts[1]

        # Check if fractional part is non-zero
        if fractional_part:
            # Round to nearest integer
            return str(round(float(value)))
        else:
            # No fractional part, return as is
            return value

